\tselect HAVE_FUNCTION_ERROR_INJECTION\n\tselect HAVE_KRETPROBES\n\tselect HAVE_RETHOOK\n\tselect HAVE_KLP_BUILD\t\t\tif X86_64\n\tselect HAVE_LIVEPATCH\t\t\tif X86_64\n\tselect HAVE_MIXED_BREAKPOINTS_REGS\n\tselect HAVE_MOD_ARCH_SPECIFIC\n\tselect HAVE_MOVE_PMD\n\tselect HAVE_MOVE_PUD\n\tselect HAVE_NOINSTR_HACK\t\tif HAVE_OBJTOOL\n\tselect HAVE_NMI\n\tselect HAVE_NOINSTR_VALIDATION\t\tif HAVE_OBJTOOL\n\tselect HAVE_OBJTOOL\t\t\tif X86_64\n\tselect HAVE_OPTPROBES\n\tselect HAVE_PAGE_SIZE_4KB\n\tselect HAVE_PCSPKR_PLATFORM\n\tselect HAVE_PERF_EVENTS\n\tselect HAVE_PERF_EVENTS_NMI\n\tselect HAVE_HARDLOCKUP_DETECTOR_PERF\tif PERF_EVENTS && HAVE_PERF_EVENTS_NMI\n\tselect HAVE_PCI\n\tselect HAVE_PERF_REGS\n\tselect HAVE_PERF_USER_STACK_DUMP\n\tselect ASYNC_KERNEL_PGTABLE_FREE\tif IOMMU_SVA\n\tselect MMU_GATHER_RCU_TABLE_FREE\n\tselect MMU_GATHER_MERGE_VMAS\n\tselect HAVE_POSIX_CPU_TIMERS_TASK_WORK\n\tselect HAVE_REGS_AND_STACK_ACCESS_API\n\tselect HAVE_RELIABLE_STACKTRACE\t\tif UNWINDER_ORC || STACK_VALIDATION\n\tselect HAVE_FUNCTION_ARG_ACCESS_API\n\tselect HAVE_SETUP_PER_CPU_AREA\n\tselect HAVE_SOFTIRQ_ON_OWN_STACK\n\tselect HAVE_STACKPROTECTOR\n\tselect HAVE_STACK_VALIDATION\t\tif HAVE_OBJTOOL\n\tselect HAVE_STATIC_CALL\n\tselect HAVE_STATIC_CALL_INLINE\t\tif HAVE_OBJTOOL\n\tselect HAVE_PREEMPT_DYNAMIC_CALL\n\tselect HAVE_RSEQ\n\tselect HAVE_RUST\t\t\tif X86_64\n\tselect HAVE_SYSCALL_TRACEPOINTS\n\tselect HAVE_UACCESS_VALIDATION\t\tif HAVE_OBJTOOL\n\tselect HAVE_UNSTABLE_SCHED_CLOCK\n\tselect HAVE_UNWIND_USER_FP\t\tif X86_64\n\tselect HAVE_USER_RETURN_NOTIFIER\n\tselect HAVE_GENERIC_VDSO\n\tselect VDSO_GETRANDOM\t\t\tif X86_64\n\tselect HOTPLUG_PARALLEL\t\t\tif SMP && X86_64\n\tselect HOTPLUG_SMT\t\t\tif SMP\n\tselect HOTPLUG_SPLIT_STARTUP\t\tif SMP && X86_32\n\tselect IRQ_FORCED_THREADING\n\tselect LOCK_MM_AND_FIND_VMA\n\tselect NEED_PER_CPU_EMBED_FIRST_CHUNK\n\tselect NEED_PER_CPU_PAGE_FIRST_CHUNK\n\tselect NEED_SG_DMA_LENGTH\n\tselect NUMA_MEMBLKS\t\t\tif NUMA\n\tselect PCI_DOMAINS\t\t\tif PCI\n\tselect PCI_LOCKLESS_CONFIG\t\tif PCI\n\tselect PERF_EVENTS\n\tselect RTC_LIB\n\tselect RTC_MC146818_LIB\n\tselect SPARSE_IRQ\n\tselect SYSCTL_EXCEPTION_TRACE\n\tselect THREAD_INFO_IN_TASK\n\tselect TRACE_IRQFLAGS_SUPPORT\n\tselect TRACE_IRQFLAGS_NMI_SUPPORT\n\tselect USER_STACKTRACE_SUPPORT\n\tselect HAVE_ARCH_KCSAN\t\t\tif X86_64\n\tselect PROC_PID_ARCH_STATUS\t\tif PROC_FS\n\tselect HAVE_ARCH_NODE_DEV_GROUP\t\tif X86_SGX\n\tselect FUNCTION_ALIGNMENT_16B\t\tif X86_64 || X86_ALIGNMENT_16\n\tselect FUNCTION_ALIGNMENT_4B\n\timply IMA_SECURE_AND_OR_TRUSTED_BOOT    if EFI\n\tselect HAVE_DYNAMIC_FTRACE_NO_PATCHABLE\n\tselect ARCH_SUPPORTS_SCHED_SMT\t\tif SMP\n\tselect SCHED_SMT\t\t\tif SMP\n\tselect ARCH_SUPPORTS_SCHED_CLUSTER\tif SMP\n\tselect ARCH_SUPPORTS_SCHED_MC\t\tif SMP\n\tselect HAVE_SINGLE_FTRACE_DIRECT_OPS\tif X86_64 && DYNAMIC_FTRACE_WITH_DIRECT_CALLS\n\nconfig INSTRUCTION_DECODER\n\tdef_bool y\n\tdepends on KPROBES || PERF_EVENTS || UPROBES\n\nconfig OUTPUT_FORMAT\n\tstring\n\tdefault \"elf32-i386\" if X86_32\n\tdefault \"elf64-x86-64\" if X86_64\n\nconfig LOCKDEP_SUPPORT\n\tdef_bool y\n\nconfig STACKTRACE_SUPPORT\n\tdef_bool y\n\nconfig MMU\n\tdef_bool y\n\nconfig ARCH_MMAP_RND_BITS_MIN\n\tdefault 28 if 64BIT\n\tdefault 8\n\nconfig ARCH_MMAP_RND_BITS_MAX\n\tdefault 32 if 64BIT\n\tdefault 16\n\nconfig ARCH_MMAP_RND_COMPAT_BITS_MIN\n\tdefault 8\n\nconfig ARCH_MMAP_RND_COMPAT_BITS_MAX\n\tdefault 16\n\nconfig SBUS\n\tbool\n\nconfig GENERIC_ISA_DMA\n\tdef_bool y\n\tdepends on ISA_DMA_API\n\nconfig GENERIC_CSUM\n\tbool\n\tdefault y if KMSAN || KASAN\n\nconfig GENERIC_BUG\n\tdef_bool y\n\tdepends on BUG\n\tselect GENERIC_BUG_RELATIVE_POINTERS\n\nconfig GENERIC_BUG_RELATIVE_POINTERS\n\tbool\n\nconfig ARCH_MAY_HAVE_PC_FDC\n\tdef_bool y\n\tdepends on ISA_DMA_API\n\nconfig GENERIC_CALIBRATE_DELAY\n\tdef_bool y\n\nconfig ARCH_HAS_CPU_RELAX\n\tdef_bool y\n\n\n... [Diff truncated. Dropped 2392 lines] ...\n\n\t  4) pass the \"floppy=nodma\" option to the kernel\n\t  5) pass the \"mem=4M\" option to the kernel (thereby disabling\n\t  all but the first 4 MB of RAM)\n\t  6) make sure that the CPU is not over clocked.\n\t  7) read the sig11 FAQ at <http://www.bitwizard.nl/sig11/>\n\t  8) disable the cache from your BIOS settings\n\t  9) install a fan for the video card or exchange video RAM\n\t  10) install a better fan for the CPU\n\t  11) exchange RAM chips\n\t  12) exchange the motherboard.\n\n\t  To compile this driver as a module, choose M here: the\n\t  module will be called apm.\n\nif APM\n\nconfig APM_IGNORE_USER_SUSPEND\n\tbool \"Ignore USER SUSPEND\"\n\thelp\n\t  This option will ignore USER SUSPEND requests. On machines with a\n\t  compliant APM BIOS, you want to say N. However, on the NEC Versa M\n\t  series notebooks, it is necessary to say Y because of a BIOS bug.\n\nconfig APM_DO_ENABLE\n\tbool \"Enable PM at boot time\"\n\thelp\n\t  Enable APM features at boot time. From page 36 of the APM BIOS\n\t  specification: \"When disabled, the APM BIOS does not automatically\n\t  power manage devices, enter the Standby State, enter the Suspend\n\t  State, or take power saving steps in response to CPU Idle calls.\"\n\t  This driver will make CPU Idle calls when Linux is idle (unless this\n\t  feature is turned off -- see \"Do CPU IDLE calls\", below). This\n\t  should always save battery power, but more complicated APM features\n\t  will be dependent on your BIOS implementation. You may need to turn\n\t  this option off if your computer hangs at boot time when using APM\n\t  support, or if it beeps continuously instead of suspending. Turn\n\t  this off if you have a NEC UltraLite Versa 33/C or a Toshiba\n\t  T400CDT. This is off by default since most machines do fine without\n\t  this feature.\n\nconfig APM_CPU_IDLE\n\tdepends on CPU_IDLE\n\tbool \"Make CPU Idle calls when idle\"\n\thelp\n\t  Enable calls to APM CPU Idle/CPU Busy inside the kernel's idle loop.\n\t  On some machines, this can activate improved power savings, such as\n\t  a slowed CPU clock rate, when the machine is idle. These idle calls\n\t  are made after the idle loop has run for some length of time (e.g.,\n\t  333 mS). On some machines, this will cause a hang at boot time or\n\t  whenever the CPU becomes idle. (On machines with more than one CPU,\n\t  this option does nothing.)\n\nconfig APM_DISPLAY_BLANK\n\tbool \"Enable console blanking using APM\"\n\thelp\n\t  Enable console blanking using the APM. Some laptops can use this to\n\t  turn off the LCD backlight when the screen blanker of the Linux\n\t  virtual console blanks the screen. Note that this is only used by\n\t  the virtual console screen blanker, and won't turn off the backlight\n\t  when using the X Window system. This also doesn't have anything to\n\t  do with your VESA-compliant power-saving monitor. Further, this\n\t  option doesn't work for all laptops -- it might not turn off your\n\t  backlight at all, or it might print a lot of errors to the console,\n\t  especially if you are using gpm.\n\nconfig APM_ALLOW_INTS\n\tbool \"Allow interrupts during APM BIOS calls\"\n\thelp\n\t  Normally we disable external interrupts while we are making calls to\n\t  the APM BIOS as a measure to lessen the effects of a badly behaving\n\t  BIOS implementation.  The BIOS should reenable interrupts if it\n\t  needs to.  Unfortunately, some BIOSes do not -- especially those in\n\t  many of the newer IBM Thinkpads.  If you experience hangs when you\n\t  suspend, try setting this to Y.  Otherwise, say N.\n\nendif # APM\n\nsource \"drivers/cpufreq/Kconfig\"\n\nsource \"drivers/cpuidle/Kconfig\"\n\nsource \"drivers/idle/Kconfig\"\n\nendmenu\n\nmenu \"Bus options (PCI etc.)\"\n\nchoice\n\tprompt \"PCI access mode\"\n\tdepends on X86_32 && PCI\n\tdefault PCI_GOANY\n\thelp\n\t  On PCI systems, the BIOS can be used to detect the PCI devices and\n\t  determine their configuration. However, some old PCI motherboards\n\t  have BIOS bugs and may crash if this is done. Also, some embedded\n\t  PCI-based systems don't have any BIOS at all. Linux can also try to\n\t  detect the PCI hardware directly without using the BIOS.\n\n\t  With this option, you can specify how Linux should detect the\n\t  PCI devices. If you choose \"BIOS\", the BIOS will be used,\n\t  if you choose \"Direct\", the BIOS won't be used, and if you\n\t  choose \"MMConfig\", then PCI Express MMCONFIG will be used.\n\t  If you choose \"Any\", the kernel will try MMCONFIG, then the\n\t  direct access method and falls back to the BIOS if that doesn't\n\t  work. If unsure, go with the default, which is \"Any\".\n\nconfig PCI_GOBIOS\n\tbool \"BIOS\"\n\nconfig PCI_GOMMCONFIG\n\tbool \"MMConfig\"\n\nconfig PCI_GODIRECT\n\tbool \"Direct\"\n\nconfig PCI_GOOLPC\n\tbool \"OLPC XO-1\"\n\tdepends on OLPC\n\nconfig PCI_GOANY\n\tbool \"Any\"\n\nendchoice\n\nconfig PCI_BIOS\n\tdef_bool y\n\tdepends on X86_32 && PCI && (PCI_GOBIOS || PCI_GOANY)\n\n# x86-64 doesn't support PCI BIOS access from long mode so always go direct.\nconfig PCI_DIRECT\n\tdef_bool y\n\tdepends on PCI && (X86_64 || (PCI_GODIRECT || PCI_GOANY || PCI_GOOLPC || PCI_GOMMCONFIG))\n\nconfig PCI_MMCONFIG\n\tbool \"Support mmconfig PCI config space access\" if X86_64\n\tdefault y\n\tdepends on PCI && (ACPI || JAILHOUSE_GUEST)\n\tdepends on X86_64 || (PCI_GOANY || PCI_GOMMCONFIG)\n\thelp\n\t  Add support for accessing the PCI configuration space as a memory\n\t  mapped area. It is the recommended method if the system supports\n\t  this (it must have PCI Express and ACPI for it to be available).\n\n\t  In the unlikely case that enabling this configuration option causes\n\t  problems, the mechanism can be switched off with the 'pci=nommconf'\n\t  command line parameter.\n\n\t  Say N only if you are sure that your platform does not support this\n\t  access method or you have problems caused by it.\n\n\t  Say Y otherwise.\n\nconfig PCI_OLPC\n\tdef_bool y\n\tdepends on PCI && OLPC && (PCI_GOOLPC || PCI_GOANY)\n\nconfig PCI_XEN\n\tdef_bool y\n\tdepends on PCI && XEN\n\nconfig MMCONF_FAM10H\n\tdef_bool y\n\tdepends on X86_64 && PCI_MMCONFIG && ACPI\n\nconfig PCI_CNB20LE_QUIRK\n\tbool \"Read PCI host bridge windows from the CNB20LE chipset\" if EXPERT\n\tdepends on X86_32 && PCI\n\thelp\n\t  Read the PCI windows out of the CNB20LE host bridge. This allows\n\t  PCI hotplug to work on systems with the CNB20LE chipset which do\n\t  not have ACPI.\n\n\t  The ServerWorks (later Broadcom) CNB20LE was a chipset designed\n\t  most probably only for Pentium III.\n\n\t  To find out if you have such a chipset, search for a PCI device with\n\t  1166:0009 PCI IDs, for example by executing\n\t\tlspci -nn | grep '1166:0009'\n\t  The code is inactive if there is none.\n\n\t  There's no public spec for this chipset, and this functionality\n\t  is known to be incomplete.\n\n\t  You should say N unless you know you need this.\n\nconfig ISA_BUS\n\tbool \"ISA bus support on modern systems\" if EXPERT\n\thelp\n\t  Expose ISA bus device drivers and options available for selection and\n\t  configuration. Enable this option if your target machine has an ISA\n\t  bus. ISA is an older system, displaced by PCI and newer bus\n\t  architectures -- if your target machine is modern, it probably does\n\t  not have an ISA bus.\n\n\t  If unsure, say N.\n\n# x86_64 have no ISA slots, but can have ISA-style DMA.\nconfig ISA_DMA_API\n\tbool \"ISA-style DMA support\" if (X86_64 && EXPERT)\n\tdefault y\n\thelp\n\t  Enables ISA-style DMA support for devices requiring such controllers.\n\t  If unsure, say Y.\n\nif X86_32\n\nconfig ISA\n\tbool \"ISA support\"\n\thelp\n\t  Find out whether you have ISA slots on your motherboard.  ISA is the\n\t  name of a bus system, i.e. the way the CPU talks to the other stuff\n\t  inside your box.  Other bus systems are PCI, EISA, MicroChannel\n\t  (MCA) or VESA.  ISA is an older system, now being displaced by PCI;\n\t  newer boards don't support it.  If you have ISA, say Y, otherwise N.\n\nconfig SCx200\n\ttristate \"NatSemi SCx200 support\"\n\thelp\n\t  This provides basic support for National Semiconductor's\n\t  (now AMD's) Geode processors.  The driver probes for the\n\t  PCI-IDs of several on-chip devices, so its a good dependency\n\t  for other scx200_* drivers.\n\n\t  If compiled as a module, the driver is named scx200.\n\nconfig SCx200HR_TIMER\n\ttristate \"NatSemi SCx200 27MHz High-Resolution Timer Support\"\n\tdepends on SCx200\n\tdefault y\n\thelp\n\t  This driver provides a clocksource built upon the on-chip\n\t  27MHz high-resolution timer.  Its also a workaround for\n\t  NSC Geode SC-1100's buggy TSC, which loses time when the\n\t  processor goes idle (as is done by the scheduler).  The\n\t  other workaround is idle=poll boot option.\n\nconfig OLPC\n\tbool \"One Laptop Per Child support\"\n\tdepends on !X86_PAE\n\tselect GPIOLIB\n\tselect OF\n\tselect OF_PROMTREE\n\tselect IRQ_DOMAIN\n\tselect OLPC_EC\n\thelp\n\t  Add support for detecting the unique features of the OLPC\n\t  XO hardware.\n\nconfig OLPC_XO1_PM\n\tbool \"OLPC XO-1 Power Management\"\n\tdepends on OLPC && MFD_CS5535=y && PM_SLEEP\n\thelp\n\t  Add support for poweroff and suspend of the OLPC XO-1 laptop.\n\nconfig OLPC_XO1_RTC\n\tbool \"OLPC XO-1 Real Time Clock\"\n\tdepends on OLPC_XO1_PM && RTC_DRV_CMOS\n\thelp\n\t  Add support for the XO-1 real time clock, which can be used as a\n\t  programmable wakeup source.\n\nconfig OLPC_XO1_SCI\n\tbool \"OLPC XO-1 SCI extras\"\n\tdepends on OLPC && OLPC_XO1_PM && GPIO_CS5535=y\n\tdepends on INPUT=y\n\tselect POWER_SUPPLY\n\thelp\n\t  Add support for SCI-based features of the OLPC XO-1 laptop:\n\t   - EC-driven system wakeups\n\t   - Power button\n\t   - Ebook switch\n\t   - Lid switch\n\t   - AC adapter status updates\n\t   - Battery status updates\n\nconfig OLPC_XO15_SCI\n\tbool \"OLPC XO-1.5 SCI extras\"\n\tdepends on OLPC && ACPI\n\tselect POWER_SUPPLY\n\thelp\n\t  Add support for SCI-based features of the OLPC XO-1.5 laptop:\n\t   - EC-driven system wakeups\n\t   - AC adapter status updates\n\t   - Battery status updates\n\nconfig GEODE_COMMON\n\tbool\n\nconfig ALIX\n\tbool \"PCEngines ALIX System Support (LED setup)\"\n\tselect GPIOLIB\n\tselect GEODE_COMMON\n\thelp\n\t  This option enables system support for the PCEngines ALIX.\n\t  At present this just sets up LEDs for GPIO control on\n\t  ALIX2/3/6 boards.  However, other system specific setup should\n\t  get added here.\n\n\t  Note: You must still enable the drivers for GPIO and LED support\n\t  (GPIO_CS5535 & LEDS_GPIO) to actually use the LEDs\n\n\t  Note: You have to set alix.force=1 for boards with Award BIOS.\n\nconfig NET5501\n\tbool \"Soekris Engineering net5501 System Support (LEDS, GPIO, etc)\"\n\tselect GPIOLIB\n\tselect GEODE_COMMON\n\thelp\n\t  This option enables system support for the Soekris Engineering net5501.\n\nconfig GEOS\n\tbool \"Traverse Technologies GEOS System Support (LEDS, GPIO, etc)\"\n\tselect GPIOLIB\n\tselect GEODE_COMMON\n\tdepends on DMI\n\thelp\n\t  This option enables system support for the Traverse Technologies GEOS.\n\nconfig TS5500\n\tbool \"Technologic Systems TS-5500 platform support\"\n\tdepends on MELAN\n\tselect CHECK_SIGNATURE\n\tselect NEW_LEDS\n\tselect LEDS_CLASS\n\thelp\n\t  This option enables system support for the Technologic Systems TS-5500.\n\nendif # X86_32\n\nconfig AMD_NB\n\tdef_bool y\n\tdepends on AMD_NODE\n\nconfig AMD_NODE\n\tdef_bool y\n\tdepends on CPU_SUP_AMD && PCI\n\nendmenu\n\nmenu \"Binary Emulations\"\n\nconfig IA32_EMULATION\n\tbool \"IA32 Emulation\"\n\tdepends on X86_64\n\tselect ARCH_WANT_OLD_COMPAT_IPC\n\tselect BINFMT_ELF\n\tselect COMPAT_OLD_SIGACTION\n\thelp\n\t  Include code to run legacy 32-bit programs under a\n\t  64-bit kernel. You should likely turn this on, unless you're\n\t  100% sure that you don't have any 32-bit programs left.\n\nconfig IA32_EMULATION_DEFAULT_DISABLED\n\tbool \"IA32 emulation disabled by default\"\n\tdefault n\n\tdepend