OR && HOTPLUG_CPU\n\tselect ARCH_32BIT_OFF_T\t\t\tif X86_32\n\tselect ARCH_CLOCKSOURCE_INIT\n\tselect ARCH_CONFIGURES_CPU_MITIGATIONS\n\tselect ARCH_CORRECT_STACKTRACE_ON_KRETPROBE\n\tselect ARCH_ENABLE_HUGEPAGE_MIGRATION if X86_64 && HUGETLB_PAGE && MIGRATION\n\tselect ARCH_ENABLE_MEMORY_HOTPLUG if X86_64\n\tselect ARCH_ENABLE_MEMORY_HOTREMOVE if MEMORY_HOTPLUG\n\tselect ARCH_ENABLE_SPLIT_PMD_PTLOCK if (PGTABLE_LEVELS > 2) && (X86_64 || X86_PAE)\n\tselect ARCH_ENABLE_THP_MIGRATION if X86_64 && TRANSPARENT_HUGEPAGE\n\tselect ARCH_HAS_ACPI_TABLE_UPGRADE\tif ACPI\n\tselect ARCH_HAS_CPU_ATTACK_VECTORS\tif CPU_MITIGATIONS\n\tselect ARCH_HAS_CACHE_LINE_SIZE\n\tselect ARCH_HAS_CPU_CACHE_INVALIDATE_MEMREGION\n\tselect ARCH_HAS_CPU_FINALIZE_INIT\n\tselect ARCH_HAS_CPU_PASID\t\tif IOMMU_SVA\n\tselect ARCH_HAS_CURRENT_STACK_POINTER\n\tselect ARCH_HAS_DEBUG_VIRTUAL\n\tselect ARCH_HAS_DEBUG_VM_PGTABLE\tif !X86_PAE\n\tselect ARCH_HAS_DEVMEM_IS_ALLOWED\n\tselect ARCH_HAS_DMA_OPS\t\t\tif GART_IOMMU || XEN\n\tselect ARCH_HAS_EARLY_DEBUG\t\tif KGDB\n\tselect ARCH_HAS_ELF_RANDOMIZE\n\tselect ARCH_HAS_EXECMEM_ROX\t\tif X86_64 && STRICT_MODULE_RWX\n\tselect ARCH_HAS_FAST_MULTIPLIER\n\tselect ARCH_HAS_FORTIFY_SOURCE\n\tselect ARCH_HAS_GCOV_PROFILE_ALL\n\tselect ARCH_HAS_KCOV\t\t\tif X86_64\n\tselect ARCH_HAS_KERNEL_FPU_SUPPORT\n\tselect ARCH_HAS_MEM_ENCRYPT\n\tselect ARCH_HAS_MEMBARRIER_SYNC_CORE\n\tselect ARCH_HAS_NMI_SAFE_THIS_CPU_OPS\n\tselect ARCH_HAS_NON_OVERLAPPING_ADDRESS_SPACE\n\tselect ARCH_HAS_PMEM_API\t\tif X86_64\n\tselect ARCH_HAS_PREEMPT_LAZY\n\tselect ARCH_HAS_PTDUMP\n\tselect ARCH_HAS_PTE_SPECIAL\n\tselect ARCH_HAS_HW_PTE_YOUNG\n\tselect ARCH_HAS_NONLEAF_PMD_YOUNG\tif PGTABLE_LEVELS > 2\n\tselect ARCH_HAS_UACCESS_FLUSHCACHE\tif X86_64\n\tselect ARCH_HAS_COPY_MC\t\t\tif X86_64\n\tselect ARCH_HAS_SET_MEMORY\n\tselect ARCH_HAS_SET_DIRECT_MAP\n\tselect ARCH_HAS_STRICT_KERNEL_RWX\n\tselect ARCH_HAS_STRICT_MODULE_RWX\n\tselect ARCH_HAS_SYNC_CORE_BEFORE_USERMODE\n\tselect ARCH_HAS_SYSCALL_WRAPPER\n\tselect ARCH_HAS_UBSAN\n\tselect ARCH_HAS_DEBUG_WX\n\tselect ARCH_HAS_ZONE_DMA_SET if EXPERT\n\tselect ARCH_HAVE_NMI_SAFE_CMPXCHG\n\tselect ARCH_HAVE_EXTRA_ELF_NOTES\n\tselect ARCH_MHP_MEMMAP_ON_MEMORY_ENABLE\n\tselect ARCH_MIGHT_HAVE_ACPI_PDC\t\tif ACPI\n\tselect ARCH_MIGHT_HAVE_PC_PARPORT\n\tselect ARCH_MIGHT_HAVE_PC_SERIO\n\tselect ARCH_STACKWALK\n\tselect ARCH_SUPPORTS_ACPI\n\tselect ARCH_SUPPORTS_ATOMIC_RMW\n\tselect ARCH_SUPPORTS_DEBUG_PAGEALLOC\n\tselect ARCH_SUPPORTS_HUGETLBFS\n\tselect ARCH_SUPPORTS_PAGE_TABLE_CHECK\tif X86_64\n\tselect ARCH_SUPPORTS_NUMA_BALANCING\tif X86_64\n\tselect ARCH_SUPPORTS_KMAP_LOCAL_FORCE_MAP\tif NR_CPUS <= 4096\n\tselect ARCH_SUPPORTS_CFI\t\tif X86_64\n\tselect ARCH_USES_CFI_TRAPS\t\tif X86_64 && CFI\n\tselect ARCH_SUPPORTS_LTO_CLANG\n\tselect ARCH_SUPPORTS_LTO_CLANG_THIN\n\tselect ARCH_SUPPORTS_RT\n\tselect ARCH_SUPPORTS_AUTOFDO_CLANG\n\tselect ARCH_SUPPORTS_PROPELLER_CLANG    if X86_64\n\tselect ARCH_USE_BUILTIN_BSWAP\n\tselect ARCH_USE_CMPXCHG_LOCKREF\t\tif X86_CX8\n\tselect ARCH_USE_MEMTEST\n\tselect ARCH_USE_QUEUED_RWLOCKS\n\tselect ARCH_USE_QUEUED_SPINLOCKS\n\tselect ARCH_USE_SYM_ANNOTATIONS\n\tselect ARCH_WANT_BATCHED_UNMAP_TLB_FLUSH\n\tselect ARCH_WANT_DEFAULT_BPF_JIT\tif X86_64\n\tselect ARCH_WANTS_DYNAMIC_TASK_STRUCT\n\tselect ARCH_WANTS_NO_INSTR\n\tselect ARCH_WANT_GENERAL_HUGETLB\n\tselect ARCH_WANT_HUGE_PMD_SHARE\t\tif X86_64\n\tselect ARCH_WANT_LD_ORPHAN_WARN\n\tselect ARCH_WANT_OPTIMIZE_DAX_VMEMMAP\tif X86_64\n\tselect ARCH_WANT_OPTIMIZE_HUGETLB_VMEMMAP\tif X86_64\n\tselect ARCH_WANT_HUGETLB_VMEMMAP_PREINIT if X86_64\n\tselect ARCH_WANTS_THP_SWAP\t\tif X86_64\n\tselect ARCH_HAS_PARANOID_L1D_FLUSH\n\tselect ARCH_WANT_IRQS_OFF_ACTIVATE_MM\n\tselect BUILDTIME_TABLE_SORT\n\tselect CLKEVT_I8253\n\tselect CLOCKSOURCE_WATCHDOG\n\t# Word-size accesses may read uninitialized data past the trailing \\0\n\t# in strings and cause false KMSAN reports.\n\tselect DCACHE_WORD_ACCESS\t\tif !KMSAN\n\tselect DYNAMIC_SIGFRAME\n\tselect EDAC_ATOMIC_SCRUB\n\tselect EDAC_SUPPORT\n\tselect GENERIC_CLOCKEVENTS_BROADCAST\tif X86_64 || (X86_32 && X86_LOCAL_APIC)\n\tselect GENERIC_CLOCKEVENTS_BROADCAST_IDLE\tif GENERIC_CLOCKEVENTS_BROADCAST\n\tselect GENERIC_CLOCKEVENTS_MIN_ADJUST\n\tselect GENERIC_CMOS_UPDATE\n\tselect GENERIC_CPU_AUTOPROBE\n\tselect GENERIC_CPU_DEVICES\n\tselect GENERIC_CPU_VULNERABILITIES\n\tselect GENERIC_EARLY_IOREMAP\n\tselect GENERIC_ENTRY\n\tselect GENERIC_IOMAP\n\tselect GENERIC_IRQ_EFFECTIVE_AFF_MASK\tif SMP\n\tselect GENERIC_IRQ_MATRIX_ALLOCATOR\tif X86_LOCAL_APIC\n\tselect GENERIC_IRQ_MIGRATION\t\tif SMP\n\tselect GENERIC_IRQ_PROBE\n\tselect GENERIC_IRQ_RESERVATION_MODE\n\tselect GENERIC_IRQ_SHOW\n\tselect GENERIC_PENDING_IRQ\t\tif SMP\n\tselect GENERIC_SMP_IDLE_THREAD\n\tselect GENERIC_TIME_VSYSCALL\n\tselect GENERIC_GETTIMEOFDAY\n\tselect GENERIC_VDSO_OVERFLOW_PROTECT\n\tselect GUP_GET_PXX_LOW_HIGH\t\tif X86_PAE\n\tselect HARDIRQS_SW_RESEND\n\tselect HARDLOCKUP_CHECK_TIMESTAMP\tif X86_64\n\tselect HAS_IOPORT\n\tselect HAVE_ACPI_APEI\t\t\tif ACPI\n\tselect HAVE_ACPI_APEI_NMI\t\tif ACPI\n\tselect HAVE_ALIGNED_STRUCT_PAGE\n\tselect HAVE_ARCH_AUDITSYSCALL\n\tselect HAVE_ARCH_HUGE_VMAP\t\tif X86_64 || X86_PAE\n\tselect HAVE_ARCH_HUGE_VMALLOC\t\tif X86_64\n\tselect HAVE_ARCH_JUMP_LABEL\n\tselect HAVE_ARCH_JUMP_LABEL_RELATIVE\n\tselect HAVE_ARCH_KASAN\t\t\tif X86_64\n\tselect HAVE_ARCH_KASAN_VMALLOC\t\tif X86_64\n\tselect HAVE_ARCH_KFENCE\n\tselect HAVE_ARCH_KMSAN\t\t\tif X86_64\n\tselect HAVE_ARCH_KGDB\n\tselect HAVE_ARCH_KSTACK_ERASE\n\tselect HAVE_ARCH_MMAP_RND_BITS\t\tif MMU\n\tselect HAVE_ARCH_MMAP_RND_COMPAT_BITS\tif MMU && COMPAT\n\tselect HAVE_ARCH_COMPAT_MMAP_BASES\tif MMU && COMPAT\n\tselect HAVE_ARCH_PREL32_RELOCATIONS\n\tselect HAVE_ARCH_SECCOMP_FILTER\n\tselect HAVE_ARCH_THREAD_STRUCT_WHITELIST\n\tselect HAVE_ARCH_TRACEHOOK\n\tselect HAVE_ARCH_TRANSPARENT_HUGEPAGE\n\tselect HAVE_ARCH_TRANSPARENT_HUGEPAGE_PUD if X86_64\n\tselect HAVE_ARCH_USERFAULTFD_WP         if X86_64 && USERFAULTFD\n\tselect HAVE_ARCH_USERFAULTFD_MINOR\tif X86_64 && USERFAULTFD\n\tselect HAVE_ARCH_VMAP_STACK\t\tif X86_64\n\tselect HAVE_ARCH_RANDOMIZE_KSTACK_OFFSET\n\tselect HAVE_ARCH_WITHIN_STACK_FRAMES\n\tselect HAVE_ASM_MODVERSIONS\n\tselect HAVE_CMPXCHG_DOUBLE\n\tselect HAVE_CMPXCHG_LOCAL\n\tselect HAVE_CONTEXT_TRACKING_USER\t\tif X86_64\n\tselect HAVE_CONTEXT_TRACKING_USER_OFFSTACK\tif HAVE_CONTEXT_TRACKING_USER\n\tselect HAVE_C_RECORDMCOUNT\n\tselect HAVE_OBJTOOL_MCOUNT\t\tif HAVE_OBJTOOL\n\tselect HAVE_OBJTOOL_NOP_MCOUNT\t\tif HAVE_OBJTOOL_MCOUNT\n\tselect HAVE_BUILDTIME_MCOUNT_SORT\n\tselect HAVE_DEBUG_KMEMLEAK\n\tselect HAVE_DMA_CONTIGUOUS\n\tselect HAVE_DYNAMIC_FTRACE\n\tselect HAVE_DYNAMIC_FTRACE_WITH_REGS\n\tselect HAVE_DYNAMIC_FTRACE_WITH_ARGS\tif X86_64\n\tselect HAVE_FTRACE_REGS_HAVING_PT_REGS\tif X86_64\n\tselect HAVE_DYNAMIC_FTRACE_WITH_DIRECT_CALLS\n\tselect HAVE_DYNAMIC_FTRACE_WITH_JMP\tif X86_64\n\tselect HAVE_SAMPLE_FTRACE_DIRECT\tif X86_64\n\tselect HAVE_SAMPLE_FTRACE_DIRECT_MULTI\tif X86_64\n\tselect HAVE_EBPF_JIT\n\tselect HAVE_EFFICIENT_UNALIGNED_ACCESS\n\tselect HAVE_EISA\t\t\tif X86_32\n\tselect HAVE_EXIT_THREAD\n\tselect HAVE_GENERIC_TIF_BITS\n\tselect HAVE_GUP_FAST\n\tselect HAVE_FENTRY\t\t\tif X86_64 || DYNAMIC_FTRACE\n\tselect HAVE_FTRACE_GRAPH_FUNC\t\tif HAVE_FUNCTION_GRAPH_TRACER\n\tselect HAVE_FUNCTION_GRAPH_FREGS\tif HAVE_FUNCTION_GRAPH_TRACER\n\tselect HAVE_FUNCTION_GRAPH_TRACER\tif X86_32 || (X86_64 && DYNAMIC_FTRACE)\n\tselect HAVE_FUNCTION_TRACER\n\tselect HAVE_GCC_PLUGINS\n\tselect HAVE_HW_BREAKPOINT\n\tselect HAVE_IOREMAP_PROT\n\tselect HAVE_IRQ_EXIT_ON_IRQ_STACK\tif X86_64\n\tselect HAVE_IRQ_TIME_ACCOUNTING\n\tselect HAVE_JUMP_LABEL_HACK\t\tif HAVE_OBJTOOL\n\tselect HAVE_KERNEL_BZIP2\n\tselect HAVE_KERNEL_GZIP\n\tselect HAVE_KERNEL_LZ4\n\tselect HAVE_KERNEL_LZMA\n\tselect HAVE_KERNEL_LZO\n\tselect HAVE_KERNEL_XZ\n\tselect HAVE_KERNEL_ZSTD\n\tselect HAVE_KPROBES\n\tselect HAVE_KPROBES_ON_FTRACE\n\tselect HAVE_FUNCTION_ERROR_INJECTION\n\tselect HAVE_KRETPROBES\n\tselect HAVE_RETHOOK\n\tselect HAVE_KLP_BUILD\t\t\tif X86_64\n\tselect HAVE_LIVEPATCH\t\t\tif X86_64\n\tselect HAVE_MIXED_BREAKPOINTS_REGS\n\tselect HAVE_MOD_ARCH_SPECIFIC\n\tselect HAVE_MOVE_PMD\n\tselect HAVE_MOVE_PUD\n\tselect HAVE_NOINSTR_HACK\t\tif HAVE_OBJTOOL\n\tselect HAVE_NMI\n\tselect HAVE_NOINSTR_VALIDATION\t\tif HAVE_OBJTOOL\n\tselect HAVE_OBJTOOL\t\t\tif X86_64\n\tselect HAVE_OPTPROBES\n\tselect HAVE_PAGE_SIZE_4KB\n\tselect HAVE_PCSPKR_PLATFORM\n\tselect HAVE_PERF_EVENTS\n\tselect HAVE_PERF_EVENTS_NMI\n\tselect HAVE_HARDLOCKUP_DETECTOR_PERF\tif PERF_EVENTS && HAVE_PERF_EVENTS_NMI\n\tselect HAVE_PCI\n\tselect HAVE_PERF_REGS\n\tselect HAVE_PERF_USER_STACK_DUMP\n\tselect ASYNC_KERNEL_PGTABLE_FREE\tif IOMMU_SVA\n\tselect MMU_GATHER_RCU_TABLE_FREE\n\tselect MMU_GATHER_MERGE_VMAS\n\tselect HAVE_POSIX_CPU_TIMERS_TASK_WORK\n\tselect HAVE_REGS_AND_STACK_ACCESS_API\n\tselect HAVE_RELIABLE_STACKTRACE\t\tif UNWINDER_ORC || STACK_VALIDATION\n\tselect HAVE_FUNCTION_ARG_ACCESS_API\n\tselect HAVE_SETUP_PER_CPU_AREA\n\tselect HAVE_SOFTIRQ_ON_OWN_STACK\n\tselect HAVE_STACKPROTECTOR\n\tselect HAVE_STACK_VALIDATION\t\tif HAVE_OBJTOOL\n\tselect HAVE_STATIC_CALL\n\tselect HAVE_STATIC_CALL_INLINE\t\tif HAVE_OBJTOOL\n\tselect HAVE_PREEMPT_DYNAMIC_CALL\n\tselect HAVE_RSEQ\n\tselect HAVE_RUST\t\t\tif X86_64\n\tselect HAVE_SYSCALL_TRACEPOINTS\n\tselect HAVE_UACCESS_VALIDATION\t\tif HAVE_OBJTOOL\n\tselect HAVE_UNSTABLE_SCHED_CLOCK\n\tselect HAVE_UNWIND_USER_FP\t\tif X86_64\n\tselect HAVE_USER_RETURN_NOTIFIER\n\tselect HAVE_GENERIC_VDSO\n\tselect VDSO_GETRANDOM\t\t\tif X86_64\n\tselect HOTPLUG_PARALLEL\t\t\tif SMP && X86_64\n\tselect HOTPLUG_SMT\t\t\tif SMP\n\tselect HOTPLUG_SPLIT_STARTUP\t\tif SMP && X86_32\n\tselect IRQ_FORCED_THREADING\n\tselect LOCK_MM_AND_FIND_VMA\n\tselect NEED_PER_CPU_EMBED_FIRST_CHUNK\n\tselect NEED_PER_CPU_PAGE_FIRST_CHUNK\n\tselect NEED_SG_DMA_LENGTH\n\tselect NUMA_MEMBLKS\t\t\tif NUMA\n\tselect PCI_DOMAINS\t\t\tif PCI\n\tselect PCI_LOCKLESS_CONFIG\t\tif PCI\n\tselect PERF_EVENTS\n\tselect RTC_LIB\n\tselect RTC_MC146818_LIB\n\tselect SPARSE_IRQ\n\tselect SYSCTL_EXCEPTION_TRACE\n\tselect THREAD_INFO_IN_TASK\n\tselect TRACE_IRQFLAGS_SUPPORT\n\tselect TRACE_IRQFLAGS_NMI_SUPPORT\n\tselect USER_STACKTRACE_SUPPORT\n\tselect HAVE_ARCH_KCSAN\t\t\tif X86_64\n\tselect PROC_PID_ARCH_STATUS\t\tif PROC_FS\n\tselect HAVE_ARCH_NODE_DEV_GROUP\t\tif X86_SGX\n\tselect FUNCTION_ALIGNMENT_16B\t\tif X86_64 || X86_ALIGNMENT_16\n\tselect FUNCTION_ALIGNMENT_4B\n\timply IMA_SECURE_AND_OR_TRUSTED_BOOT    if EFI\n\tselect HAVE_DYNAMIC_FTRACE_NO_PATCHABLE\n\tselect ARCH_SUPPORTS_SCHED_SMT\t\tif SMP\n\tselect SCHED_SMT\t\t\tif SMP\n\tselect ARCH_SUPPORTS_SCHED_CLUSTER\tif SMP\n\tselect ARCH_SUPPORTS_SCHED_MC\t\tif SMP\n\tselect HAVE_SINGLE_FTRACE_DIRECT_OPS\tif X86_64 && DYNAMIC_FTRACE_WITH_DIRECT_CALLS\n\nconfig INSTRUCTION_DECODER\n\tdef_bool y\n\tdepends on KPROBES || PERF_EVENTS || UPROBES\n\nconfig OUTPUT_FORMAT\n\tstring\n\tdefault \"elf32-i386\" if X86_32\n\tdefault \"elf64-x86-64\" if X86_64\n\nconfig LOCKDEP_SUPPORT\n\tdef_bool y\n\nconfig STACKTRACE_SUPPORT\n\tdef_bool y\n\nconfig MMU\n\tdef_bool y\n\nconfig ARCH_MMAP_RND_BITS_MIN\n\tdefault 28 if 64BIT\n\tdefault 8\n\nconfig ARCH_MMAP_RND_BITS_MAX\n\tdefault 32 if 64BIT\n\tdefault 16\n\nconfig ARCH_MMAP_RND_COMPAT_BITS_MIN\n\tdefault 8\n\nconfig ARCH_MMAP_RND_COMPAT_BITS_MAX\n\tdefault 16\n\nconfig SBUS\n\tbool\n\nconfig GENERIC_ISA_DMA\n\tdef_bool y\n\tdepends on ISA_DMA_API\n\nconfig GENERIC_CSUM\n\tbool\n\tdefault y if KMSAN || KASAN\n\nconfig GENERIC_BUG\n\tdef_bool y\n\tdepends on BUG\n\tselect GENERIC_BUG_RELATIVE_POINTERS\n\nconfig GENERIC_BUG_RELATIVE_POINTERS\n\tbool\n\nconfig ARCH_MAY_HAVE_PC_FDC\n\tdef_bool y\n\tdepends on ISA_DMA_API\n\nconfig GENERIC_CALIBRATE_DELAY\n\tdef_bool y\n\nconfig ARCH_HAS_CPU_RELAX\n\tdef_bool y\n\n\n... [Diff truncated. Dropped 2392 lines] ...\n\n\t  4) pass the \"floppy=nodma\" option to the kernel\n\t  5) pass the \"mem=4M\" option to the kernel (thereby disabling\n\t  all but the first 4 MB of RAM)\n\t  6) make sure that the CPU is not over clocked.\n\t  7) read the sig11 FAQ at <http://www.bitwizard.nl/sig11/>\n\t  8) disable the cache from your BIOS settings\n\t  9) install a fan for the video card or exchange video RAM\n\t  10) install a better fan for the CPU\n\t  11) exchange RAM chips\n\t  12) exchange the motherboard.\n\n\t  To compile this driver as a module, choose M here: the\n\t  module will be called apm.\n\nif APM\n\nconfig APM_IGNORE_USER_SUSPEND\n\tbool \"Ignore USER SUSPEND\"\n\thelp\n\t  This option will ignore USER SUSPEND requests. On machines with a\n\t  compliant APM BIOS, you want to say N. However, on the NEC Versa M\n\t  series notebooks, it is necessary to say Y because of a BIOS bug.\n\nconfig APM_DO_ENABLE\n\tbool \"Enable PM at boot time\"\n\thelp\n\t  Enable APM features at boot time. From page 36 of the APM BIOS\n\t  specification: \"When disabled, the APM BIOS does not automatically\n\t  power manage devices, enter the Standby State, enter the Suspend\n\t  State, or take power saving steps in response to CPU Idle calls.\"\n\t  This driver will make CPU Idle calls when Linux is idle (unless this\n\t  feature is turned off -- see \"Do CPU IDLE calls\", below). This\n\t  should always save battery power, but more complicated APM features\n\t  will be dependent on your BIOS implementation. You may need to turn\n\t  this option off if your computer hangs at boot time when using APM\n\t  support, or if it beeps continuously instead of suspending. Turn\n\t  this off if you have a NEC UltraLite Versa 33/C or a Toshiba\n\t  T400CDT. This is off by default since most machines do fine without\n\t  this feature.\n\nconfig APM_CPU_IDLE\n\tdepends on CPU_IDLE\n\tbool \"Make CPU Idle calls when idle\"\n\thelp\n\t  Enable calls to APM CPU Idle/CPU Busy inside the kernel's idle loop.\n\t  On some machines, this can activate improved power savings, such as\n\t  a slowed CPU clock rate, when the machine is idle. These idle calls\n\t  are made after the idle loop has run for some length of time (e.g.,\n\t  333 mS). On some machines, this will cause a hang at boot time or\n\t  whenever the CPU becomes idle. (On machines with more than one CPU,\n\t  this option does nothing.)\n\nconfig APM_DISPLAY_BLANK\n\tbool \"Enable console blanking using APM\"\n\thelp\n\t  Enable console blanking using the APM. Some laptops can use this to\n\t  turn off the LCD backlight when the screen blanker of the Linux\n\t  virtual console blanks the screen. Note that this is only used by\n\t  the virtual console screen blanker, and won't turn off the backlight\n\t  when using the X Window system. This also doesn't have anything to\n\t  do with your VESA-compliant power-saving monitor. Further, this\n\t  option doesn't work for all laptops -- it might not turn off your\n\t  backlight at all, or it might print a lot of errors to the console,\n\t  especially if you are using gpm.\n\nconfig APM_ALLOW_INTS\n\tbool \"Allow interrupts during APM BIOS calls\"\n\thelp\n\t  Normally we disable external interrupts while we are making calls to\n\t  the APM BIOS as a measure to lessen the effects of a badly behaving\n\t  BIOS implementation.  The BIOS should reenable interrupts if it\n\t  needs to.  Unfortunately, some BIOSes do not -- especially those in\n\t  many of the newer IBM Thinkpads.  If you experience hangs when you\n\t  suspend, try setting this to Y.  Otherwise, say N.\n\nendif # APM\n\nsource \"drivers/cpufreq/Kconfig\"\n\nsource \"drivers/cpuidle/Kconfig\"\n\nsource \"drivers/idle/Kconfig\"\n\nendmenu\n\nmenu \"Bus options (PCI etc.)\"\n\nchoice\n\tprompt \"PCI access mode\"\n\tdepends on X86_32 && PCI\n\tdefault PCI_GOANY\n\thelp\n\t  On PCI systems, the BIOS can be used to detect the PCI devices and\n\t  determine their configuration. However, some old PCI motherboards\n\t  have BIOS bugs and may crash if t